// Identifica grupo e extrai mensagem da Evolution API
const body = $input.first().json;

// Mapeia grupos para projetos
const GRUPOS = {
  'K2Con': 'k2con',
  'EG Food': 'eg_food',
  'Gestao EG': 'gestao_eg',
  'MKT EG': 'mkt_eg',
  'Quickbooks': 'quickbooks'
};

const nomeGrupo = body.data?.pushName || body.data?.notifyName || 'EG Geral';
const projeto = GRUPOS[nomeGrupo] || 'geral';
const tipoMensagem = body.data?.message?.audioMessage ? 'audio' : 'texto';
const mensagemTexto = body.data?.message?.conversation || body.data?.message?.extendedTextMessage?.text || '';
const audioUrl = body.data?.message?.audioMessage ? body.data?.message?.url : null;

return [{
  json: {
    grupo: nomeGrupo,
    projeto,
    tipo_mensagem: tipoMensagem,
    mensagem_texto: mensagemTexto,
    audio_url: audioUrl,
    remetente: body.data?.key?.remoteJid,
    timestamp: new Date().toISOString()
  }
}];
